 if(showTransport.checked){transportSegments.forEach(s=>{if(dfilter!=='all'&&!matchDay(s.day,dfilter))return;if(active!=='all'&&String(s.day)!==`D${active}`)return;if(s.midLat&&s.midLon){L.marker([s.midLat,s.midLon],{icon:costIcon(s.cost)}).bindPopup(`<strong><a href="${s.link}" target="_blank">${s.fromName} → ${s.toName}</a></strong><br><strong>Modo:</strong> ${s.mode}<br><strong>Costo:</strong> ${s.costHtml}<br>${s.note}<div class="links"><a href="${s.link}" target="_blank">Abrir tramo</a></div>`).addTo(transportLayer);}});}
