function distKm(a,b){const R=6371,dLat=(b.lat-a.lat)*Math.PI/180,dLon=(b.lon-a.lon)*Math.PI/180,la1=a.lat*Math.PI/180,la2=b.lat*Math.PI/180;const x=Math.sin(dLat/2)**2+Math.cos(la1)*Math.cos(la2)*Math.sin(dLon/2)**2;return 2*R*Math.asin(Math.sqrt(x));}
function nearestOrder(start, pts){let remaining=[...pts],cur=start,out=[];while(remaining.length){let bi=0,bd=1e9;remaining.forEach((p,i)=>{const d=distKm(cur,p);if(d<bd){bd=d;bi=i;}});let next=remaining.splice(bi,1)[0];out.push(next);cur=next;}return out;}

