function simpleCostText(i){return (i.costHtml||i.price||'Costo por definir').replace(/<[^>]*>/g,' ');}
function clickedArea(lat, lon){
  // Rough island bounding boxes. Purpose: prevent cross-island false references.
  const boxes=[
    {name:'La Graciosa', latMin:29.16, latMax:29.31, lonMin:-13.60, lonMax:-13.43},
    {name:'Lanzarote', latMin:28.80, latMax:29.26, lonMin:-13.92, lonMax:-13.33},
    {name:'Tenerife', latMin:27.93, latMax:28.62, lonMin:-16.95, lonMax:-16.05},
    {name:'Gran Canaria', latMin:27.68, latMax:28.20, lonMin:-15.86, lonMax:-15.33},
    {name:'La Gomera', latMin:28.00, latMax:28.26, lonMin:-17.38, lonMax:-17.02},
    {name:'Fuerteventura', latMin:27.95, latMax:28.82, lonMin:-14.55, lonMax:-13.75},
    {name:'El Hierro', latMin:27.60, latMax:27.90, lonMin:-18.20, lonMax:-17.85},
    {name:'La Palma', latMin:28.45, latMax:28.90, lonMin:-18.05, lonMax:-17.70}
  ];
  const hit=boxes.find(b=>lat>=b.latMin&&lat<=b.latMax&&lon>=b.lonMin&&lon<=b.lonMax);
  return hit ? hit.name : 'Mar / zona sin isla detectada';
}

function zoneDescriptor(lat, lon){
  const island = clickedArea(lat, lon);
  const ns = island==='Mar / zona sin isla detectada' ? '' : (
    lat > ({'Tenerife':28.27,'Gran Canaria':27.95,'Lanzarote':29.03,'La Graciosa':29.23,'La Gomera':28.12,'Fuerteventura':28.35,'El Hierro':27.75,'La Palma':28.67}[island] || lat) ? 'norte' : 'sur'
  );
  const ew = island==='Mar / zona sin isla detectada' ? '' : (
    lon > ({'Tenerife':-16.55,'Gran Canaria':-15.60,'Lanzarote':-13.65,'La Graciosa':-13.52,'La Gomera':-17.20,'Fuerteventura':-14.15,'El Hierro':-18.03,'La Palma':-17.88}[island] || lon) ? 'este' : 'oeste'
  );
  let terrain = 'paisaje';
  // very rough terrain cues by island and broad position; enough for image search terms, not navigation.
  if(['La Gomera','La Palma','El Hierro'].includes(island)) terrain = 'montaña senderismo miradores barrancos';
  if(island==='Tenerife' && lon < -16.72) terrain = 'Teno montaña acantilados senderismo';
  if(island==='Tenerife' && lat > 28.48 && lon > -16.35) terrain = 'Anaga laurisilva costa senderismo';
  if(island==='Gran Canaria' && lat > 27.95 && lon < -15.60) terrain = 'Agaete Tamadaba montaña costa';
  if(island==='Gran Canaria' && lat < 27.82) terrain = 'playa dunas costa sur';
  if(island==='Lanzarote' && lon < -13.70) terrain = 'volcanes Timanfaya lava paisaje';
  if(island==='Lanzarote' && lat > 29.09) terrain = 'norte Haría Famara acantilados';
  if(island==='La Graciosa') terrain = 'playas arena volcánica isla';
  if(island==='Fuerteventura') terrain = 'playas dunas costa volcánica';
  if(island==='Mar / zona sin isla detectada') terrain = 'Islas Canarias costa paisaje';
  return {island, ns, ew, terrain};
}
function semanticSearchBase(i){
  const z = zoneDescriptor(i.lat, i.lon);
  if(String(i.uid||'').startsWith('custom_')){
    if(z.island==='Mar / zona sin isla detectada'){
      return 'Islas Canarias paisaje costa mar';
    }
    return `${z.island} ${z.ns} ${z.ew} ${z.terrain} Canarias`;
  }
  return `${i.name} ${i.area||z.island} Canarias`;
}

function nearestKnownPoint(ref){
  const area = ref.area || clickedArea(ref.lat, ref.lon);
  // Only compare against loaded points on the same island. This prevents Masca/Tenerife from being used for La Gomera.
  let pool = items.filter(p=>p.lat&&p.lon&&p.area===area);
  let maxKm = 18;
  // If the clicked island has no loaded inventory, do not force a remote reference.
  if(!pool.length) return null;
  let best=null, bd=1e9;
  pool.forEach(p=>{const d=distKm(ref,p); if(d<bd){bd=d;best=p;}});
  return (best && bd<=maxKm) ? {point:best, dist:bd} : null;
}
