    googleImages: imageUrl(`${base} fotos`),
    bingImages: 'https://www.bing.com/images/search?q=' + encodeURIComponent(`${base} fotos`),
    flickr: 'https://www.flickr.com/search/?text=' + encodeURIComponent(base),
