function addCustomPoint(latlng){
  const id='custom_'+Date.now();
  const area = clickedArea(latlng.lat, latlng.lng);
  const lat = latlng.lat.toFixed(5);
  const lon = latlng.lng.toFixed(5);
  const z = zoneDescriptor(latlng.lat, latlng.lng);
  const semantic = area==='Mar / zona sin isla detectada' ? 'Islas Canarias paisaje costa mar' : `${z.island} ${z.ns} ${z.ew} ${z.terrain} Canarias`;
  const p={uid:id,id:id,name:`Punto exacto ${lat}, ${lon}`,area:area,cat:'Punto exacto marcado',kind:'custom',lat:latlng.lat,lon:latlng.lng,price:'Por definir',costHtml:'Por definir',schedule:'Horario flexible / por definir; revisar links de zona',hours:'Horario flexible / por definir; revisar links de zona',source:'Creado manualmente desde la coordenada exacta marcada en el mapa',note:`Punto exacto marcado en ${lat}, ${lon}. No se asocia ni se reemplaza por ningún punto cercano. Para imágenes se usa una búsqueda de zona: "${semantic}", pero la referencia operativa es la coordenada exacta.`,nearestId:null,nearestName:null,nearestDist:null,defaultSelected:false,planningMinutes:45,mapLink:`https://www.google.com/maps/search/?api=1&query=${latlng.lat},${latlng.lng}`,imageLink:imageUrl(`${semantic} fotos`),webLink:searchUrl(`${semantic} información turística horario precio acceso`),tiles:[],semanticBase:semantic};
  customPoints.push(p);
  savePlannerState();
  if(window.firebaseUpsertCustomPoint) window.firebaseUpsertCustomPoint(p);
  const m=L.marker([p.lat,p.lon],{icon:customIcon(),zIndexOffset:1200}).bindPopup(`<strong>${p.name}</strong><br>Punto exacto marcado<br><a href="${p.mapLink}" target="_blank">Abrir coordenada</a> · <a href="${p.imageLink}" target="_blank">Imágenes zona</a> · <a href="#" onclick="renderContext(customPoints.find(x=>x.uid==='${p.uid}'));return false;">Ver panel</a> · <a href="#" onclick="deleteCustomPoint('${p.uid}');return false;">Eliminar</a>`);
  m.on('click',()=>renderContext(p));
  m.addTo(customLayer);
  markerIndex[p.uid]=m;
  renderContext(p);
  map.setView([p.lat,p.lon],13);
}
function updateNearby(ref){
  const radius=parseFloat(document.getElementById('nearRadius').value||12);
  const refArea = ref.area || clickedArea(ref.lat, ref.lon);
  const pool=items.concat(customPoints).filter(p=>p.uid!==ref.uid && p.kind!=='hotel' && p.area===refArea);
  const near=pool.map(p=>({p, d:distKm(ref,p)})).filter(x=>x.d<=radius).sort((a,b)=>a.d-b.d).slice(0,12);
  const box=document.getElementById('nearbyPanel');
  if(!near.length){box.innerHTML='<div class="mini">No hay puntos cargados cercanos en esta misma isla dentro del radio elegido. Puedes crear puntos exactos nuevos con clic en el mapa.</div>';return;}
  box.innerHTML=near.mapbox.innerHTML=near.map(x=>`<div class="nearby-item"><strong>${x.p.name}</strong><span>${x.p.area} · ${x.p.cat||x.p.kind} · ${x.d.toFixed(1)} km</span><span>${x.p.schedule||''}</span><div><button onclick="openMapPoint('${x.p.uid}')">Ver</button><button onclick="togglePlan('${x.p.uid}')">${selectedPlan.has(x.p.uid)?'Quitar':'Agregar'}</button></div></div>`).join('');
}
function setReferenceFromContext(){
  if(!activeContext)return;
  referencePoint=activeContext;
  document.getElementById('referenceMode').value='clicked';
  updateNearby(referencePoint);
}
function deleteCustomPoint(uid){
  const idx=customPoints.findIndex(x=>x.uid===uid);
  if(idx<0)return;
  const keepCenter = map.getCenter();
  const keepZoom = map.getZoom();
  selectedPlan.delete(uid);
  if(window.firebaseDeleteCustomPoint) window.firebaseDeleteCustomPoint(uid);
  if(referencePoint && referencePoint.uid===uid) referencePoint=null;
  if(activeContext && activeContext.uid===uid) activeContext=null;
  customPoints.splice(idx,1);
  savePlannerState();
  customLayer.clearLayers();
  customPoints.forEach(p=>{
    const m=L.marker([p.lat,p.lon],{icon:customIcon(),zIndexOffset:1200}).bindPopup(`<strong>${p.name}</strong><br>Punto exacto marcado<br><a href="${p.mapLink}" target="_blank">Abrir coordenada</a> · <a href="${p.imageLink}" target="_blank">Imágenes zona</a> · <a href="#" onclick="renderContext(customPoints.find(x=>x.uid==='${p.uid}'));return false;">Ver panel</a> · <a href="#" onclick="deleteCustomPoint('${p.uid}');return false;">Eliminar</a>`);
    m.on('click',()=>renderContext(p));
    m.addTo(customLayer);
    markerIndex[p.uid]=m;
  });
  renderPlanner();
  // Do not call full render() because it refits to global bounds. Keep local exploration context.
  map.setView(keepCenter, keepZoom, {animate:false});
  document.getElementById('contextPanel').innerHTML='<div class="context-empty"><strong>Referencia eliminada</strong><br>La vista se mantiene donde estabas. Puedes seguir explorando localmente.</div>';
  document.getElementById('addContextBtn').disabled=true;
  document.getElementById('setReferenceBtn').disabled=true;
  document.getElementById('deleteContextBtn').disabled=true;
}

function directionsUrl(route){if(!route.length)return'#';const origin=encodeURIComponent(`${route[0].lat},${route[0].lon}`),dest=encodeURIComponent(`${route[route.length-1].lat},${route[route.length-1].lon}`);const wps=route.slice(1,-1).map(p=>`${p.lat},${p.lon}`).join('|');let u=`https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${dest}&travelmode=driving`;if(wps)u+='&waypoints='+encodeURIComponent(wps);return u;}
function optimizePlan(){
 customRouteLayer.clearLayers();
 const maxN=parseInt(maxPerDay.value,10);
 const selected=items.concat(customPoints).filter(i=>selectedPlan.has(i.uid) && i.kind!=='hotel');
 const hotels={'Tenerife':byId['hotel_aguere'],'Gran Canaria':byId['hotel_roca_negra'],'Lanzarote':byId['hotel_naranjos'],'La Graciosa':byId['hotel_naranjos']};
 const orderAreas=['Tenerife','Gran Canaria','Lanzarote','La Graciosa'];
 let dayNo=1, outHtml='', allBounds=[];
 orderAreas.forEach(area=>{
   let pts=selected.filter(p=>p.area===area);
   if(!pts.length)return;
   const start=(document.getElementById('referenceMode').value==='clicked' && referencePoint && (referencePoint.area===area || referencePoint.area==='Canarias')) ? referencePoint : (hotels[area]||pts[0]);
   const ordered=nearestOrder(start,pts);
   for(let i=0;i<ordered.length;i+=maxN){
     const chunk=ordered.slice(i,i+maxN);
     const route=[start,...chunk,start];
     const km=route.slice(1).reduce((sum,p,idx)=>sum+distKm(route[idx],p),0);
     const minutes=Math.round(chunk.reduce((s,p)=>s+(p.planningMinutes||60),0)+km*2.2);
     const color=['#2563eb','#16a34a','#dc2626','#7c3aed','#ca8a04','#0891b2'][dayNo%6];
     const latlngs=route.map(p=>[p.lat,p.lon]);
     L.polyline(latlngs,{color:color,weight:6,opacity:.85}).bindPopup(`<strong>Itinerario optimizado día ${dayNo}</strong><br>${area} · ${Math.round(km)} km aprox.`).addTo(customRouteLayer);
     latlngs.forEach(x=>allBounds.push(x));
     outHtml += `<div class="plan-day"><h4>Día opt. ${dayNo} · ${area}</h4><div class="mini">Ruta estimada: ${Math.round(km)} km · tiempo total aprox. ${Math.floor(minutes/60)}h${String(minutes%60).padStart(2,'0')} · máximo ${maxN} puntos fuertes</div><ol>`;
     chunk.forEach(p=>{outHtml+=`<li><a href="#" onclick="openMapPoint('${p.uid}');return false;"><strong>${p.name}</strong></a><br><span class="mini">${p.cat} · ${p.schedule} · ${p.costHtml}</span></li>`;});
     outHtml += `</ol><div class="links"><a target="_blank" href="${directionsUrl(route)}">Abrir ruta en Google Maps</a></div></div>`;
     dayNo++;
   }
 });
 planOutput.innerHTML=outHtml||'<div class="warn">No hay puntos seleccionados. Marca puntos y vuelve a optimizar.</div>';
 if(allBounds.length)map.fitBounds(L.latLngBounds(allBounds).pad(.18));
}

map.on('click', function(e){
  // Avoid creating custom point when clicking existing marker/polyline popups; Leaflet marker click does not propagate reliably, but this is acceptable map-first behavior.
  addCustomPoint(e.latlng);
});
document.getElementById('addContextBtn').onclick=function(){ if(activeContext){ selectedPlan.add(activeContext.uid); addToPlanWithPrompt(activeContext.uid); renderPlanner(); optimizePlan(); render(); }};
document.getElementById('setReferenceBtn').onclick=setReferenceFromContext;
document.getElementById('deleteContextBtn').onclick=function(){ if(activeContext && String(activeContext.uid).startsWith('custom_')) deleteCustomPoint(activeContext.uid); };
document.getElementById('nearRadius').addEventListener('input',()=>{ if(activeContext) updateNearby(activeContext); });


function showDetailTab(id){
  document.querySelectorAll('#contextPanel .detail-section').forEach(x=>x.classList.remove('active'));
  const el=document.getElementById(id); if(el)el.classList.add('active');
}
function loadPlannerState(){
  // Firebase loader runs after login. Local fallback is kept for offline/dev.
  try{
    const raw=localStorage.getItem('canariasPlannerV15');
    if(raw && !firebaseReady){
      const data=JSON.parse(raw);
      itineraryPlan=data.itineraryPlan||[];
      plannerNotes=data.plannerNotes||{};
      customPoints=data.customPoints||customPoints;
      if(window.rebuildCustomLayer) rebuildCustomLayer();
    }
  }catch(e){console.warn(e)}
}
function savePlannerState(){
  try{localStorage.setItem('canariasPlannerV15', JSON.stringify({itineraryPlan, plannerNotes, customPoints, selectedPlan:[...selectedPlan]}));}catch(e){console.warn(e)}
  if(window.firebaseSaveTripState && firebaseReady && currentTripId){
    clearTimeout(saveDebounceTimer);
    saveDebounceTimer=setTimeout(()=>window.firebaseSaveTripState(), 450);
  }
}
function rebuildCustomLayer(){
  customLayer.clearLayers();
  customPoints.forEach(p=>{
    const m=L.marker([p.lat,p.lon],{icon:customIcon(),zIndexOffset:1200}).bindPopup(`<strong>${p.name}</strong><br>Punto exacto marcado<br><a href="${p.mapLink}" target="_blank">Abrir coordenada</a> · <a href="${p.imageLink}" target="_blank">Imágenes zona</a> · <a href="#" onclick="renderContext(customPoints.find(x=>x.uid==='${p.uid}'));return false;">Ver panel</a> · <a href="#" onclick="deleteCustomPoint('${p.uid}');return false;">Eliminar</a>`);
    m.on('click',()=>renderContext(p));
    m.addTo(customLayer);
    markerIndex[p.uid]=m;
  });
}
function allPlannerItems(){return items.concat(customPoints);}
function getItem(uid){return byId[uid] || customPoints.find(x=>x.uid===uid);}
function addToPlanWithPrompt(uid){
  const p=getItem(uid); if(!p)return;
  let d=prompt('¿A qué día quieres agregarlo? Usa número 2-16 o deja vacío para Sin día:', '');
  let day=d&&d.trim()?('D'+d.replace(/^D/i,'')):'Sin día';
  const item={uid, day, order: itineraryPlan.length+1}; itineraryPlan.push(item); if(window.firebaseUpsertItineraryItem) window.firebaseUpsertItineraryItem(item, item.order); savePlannerState(); renderTimeline(); renderPlanner(); 
}
function removeFromItinerary(idx){
  const removed=itineraryPlan[idx]; if(window.firebaseDeleteItineraryItem) window.firebaseDeleteItineraryItem(removed); itineraryPlan.splice(idx,1); savePlannerState(); renderTimeline();
}
function moveItinerary(idx, dir){
  const ni=idx+dir; if(ni<0||ni>=itineraryPlan.length)return;
  [itineraryPlan[idx], itineraryPlan[ni]]=[itineraryPlan[ni], itineraryPlan[idx]]; itineraryPlan.forEach((it,i)=>{it.order=i+1;if(window.firebaseUpsertItineraryItem) window.firebaseUpsertItineraryItem(it,i+1);});
  savePlannerState(); renderTimeline();
}
function changeItineraryDay(idx, day){
  itineraryPlan[idx].day=day; if(window.firebaseUpsertItineraryItem) window.firebaseUpsertItineraryItem(itineraryPlan[idx], idx+1); savePlannerState(); renderTimeline();
}
function savePointNote(uid){
  const t=document.getElementById('noteText'); if(!t)return;
  plannerNotes[uid]=t.value; if(window.firebaseSaveNote) window.firebaseSaveNote(uid,t.value); savePlannerState(); renderTimeline();
}
function deletePointNote(uid){
  delete plannerNotes[uid]; if(window.firebaseDeleteNote) window.firebaseDeleteNote(uid); savePlannerState(); if(activeContext&&activeContext.uid===uid)renderContext(activeContext); renderTimeline();
}
function numericCostCLP(p){
  const s=String(p.price||'');
  let m=s.match(/\$([\d\.\,]+)/); if(m)return parseFloat(m[1].replaceAll('.','').replace(',',''))||0;
  m=s.match(/€\s*([\d\.,]+)/); if(m)return (parseFloat(m[1].replace('.','').replace(',','.'))||0)*1050;
  return 0;
}
function renderTimeline(){
  const box=document.getElementById('timelineBuilder'); if(!box)return;
  const enriched=itineraryPlan.map((e,idx)=>({e,idx,p:getItem(e.uid)})).filter(x=>x.p);
  const days=[...new Set(enriched.map(x=>x.e.day))].sort((a,b)=>String(a).localeCompare(String(b),'es'));
  let total=enriched.reduce((s,x)=>s+numericCostCLP(x.p),0);
  document.getElementById('statPoints').textContent=enriched.length;
  document.getElementById('statBudget').textContent=total?('$'+Math.round(total).toLocaleString('es-CL')+' CLP'):'—';
  document.getElementById('statDays').textContent=days.length;
  if(!enriched.length){box.innerHTML='<div class="warn">Aún no tienes puntos en tu plan. Selecciona un punto en el mapa y usa “Agregar al itinerario”.</div>'; renderLiveRouteBase(); return;}
  box.innerHTML=days.map(day=>{
    const arr=enriched.filter(x=>x.e.day===day);
    return `<div class="plan-day"><h4>${day}</h4>${arr.map(x=>`<div class="timeline-item"><strong><a href="#" onclick="openMapPoint('${x.p.uid}');return false;">${x.p.name}</a></strong><span class="mini">${x.p.area} · ${x.p.cat} · ${x.p.schedule||''}</span><span class="mini">${x.p.costHtml||x.p.price||''}</span>${plannerNotes[x.p.uid]?`<span class="mini"><strong>Nota:</strong> ${plannerNotes[x.p.uid]}</span>`:''}<div class="timeline-actions"><button onclick="moveItinerary(${x.idx},-1)">↑</button><button onclick="moveItinerary(${x.idx},1)">↓</button><button onclick="changeItineraryDay(${x.idx}, prompt('Nuevo día:', '${day}')||'${day}')">Cambiar día</button><button onclick="removeFromItinerary(${x.idx})">Eliminar</button><button onclick="renderContext(getItem('${x.p.uid}'))">Detalle</button></div></div>`).join('')}</div>`;
  }).join('');
  renderLiveRouteBase();
}
function buildRelated(ref){
  const box=document.getElementById('relatedPanel'); if(!box)return;
  const pool=items.filter(p=>p.uid!==ref.uid && p.area===ref.area);
  const rel=pool.map(p=>({p,d:distKm(ref,p)})).sort((a,b)=>a.d-b.d).slice(0,10);
  box.innerHTML=rel.map(x=>`<div class="related-card"><strong>${x.p.name}</strong><span>${x.p.cat} · ${x.d.toFixed(1)} km</span><div class="links"><a href="#" onclick="openMapPoint('${x.p.uid}');return false;">Ver</a><a href="#" onclick="addToPlanWithPrompt('${x.p.uid}');return false;">Agregar</a><a target="_blank" href="${x.p.webLink}">Web</a></div></div>`).join('') || '<div class="mini">Sin relacionados cargados.</div>';
}
function exportPlanJSON(){
  const data={itineraryPlan, customPoints, plannerNotes, exportedAt:new Date().toISOString()};
  const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='canarias_plan.json'; a.click();
}
function exportPlanCSV(){
  const rows=[['day','name','area','category','lat','lon','cost','schedule','note']];
  itineraryPlan.forEach(e=>{const p=getItem(e.uid); if(p)rows.push([e.day,p.name,p.area,p.cat,p.lat,p.lon,(p.price||''),(p.schedule||''),(plannerNotes[p.uid]||'')]);});
  const csv=rows.map(r=>r.map(v=>`"${String(v).replaceAll('"','""')}"`).join(',')).join('\n');
  const blob=new Blob([csv],{type:'text/csv'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='canarias_plan.csv'; a.click();
}
function copyPlanSummary(){
  const lines=itineraryPlan.map(e=>{const p=getItem(e.uid); return p?`${e.day}: ${p.name} — ${p.area} — ${p.schedule||''}`:''}).filter(Boolean);
  navigator.clipboard?.writeText(lines.join('\n')); alert('Resumen copiado.');
}
function clearSavedPlanner(){
  if(!confirm('¿Borrar plan guardado, notas y puntos custom?'))return;
  itineraryPlan=[]; plannerNotes={}; customPoints=[]; localStorage.removeItem('canariasPlannerV15'); rebuildCustomLayer(); renderTimeline(); renderPlanner(); render();
}

